1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return an empty grid when given an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with 0 neighbors (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
16	    const sortCells = (cells: [number, number][]) =>
17	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
19	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
20	  });
21	  it("should keep a block still life unchanged (each cell has 3 neighbors, survives)", () => {
22	    const sortCells = (cells: [number, number][]) =>
23	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
24	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
25	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
26	  });
27	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
28	  it.todo("should kill the center of a full 3x3 block due to overpopulation while corners survive");
29	  it.todo("should handle negative coordinates correctly");
30	});
31

1	export type Cell = [number, number];
2	
3	const encodeCell = ([x, y]: Cell): string => `${x},${y}`;
4	const decodeCell = (key: string): Cell => {
5	  const [x, y] = key.split(",").map(Number);
6	  return [x, y];
7	};
8	
9	const neighborsOf = ([x, y]: Cell): Cell[] => {
10	  const neighbors: Cell[] = [];
11	  for (let dx = -1; dx <= 1; dx++) {
12	    for (let dy = -1; dy <= 1; dy++) {
13	      if (dx === 0 && dy === 0) continue;
14	      neighbors.push([x + dx, y + dy]);
15	    }
16	  }
17	  return neighbors;
18	};
19	
20	const survives = (isAlive: boolean, liveNeighborCount: number): boolean =>
21	  (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) ||
22	  (!isAlive && liveNeighborCount === 3);
23	
24	export function nextGeneration(liveCells: Cell[]): Cell[] {
25	  const liveSet = new Set(liveCells.map(encodeCell));
26	  const candidates = new Set<string>();
27	  for (const cell of liveCells) {
28	    for (const neighbor of neighborsOf(cell)) {
29	      candidates.add(encodeCell(neighbor));
30	    }
31	    candidates.add(encodeCell(cell));
32	  }
33	  const result: Cell[] = [];
34	  for (const key of candidates) {
35	    const cell = decodeCell(key);
36	    const liveNeighborCount = neighborsOf(cell).filter((n) =>
37	      liveSet.has(encodeCell(n))
38	    ).length;
39	    if (survives(liveSet.has(key), liveNeighborCount)) {
40	      result.push(cell);
41	    }
42	  }
43	  return result;
44	}
